/**
 * API para iniciar render de vídeo - FASE 2 REAL
 * POST /api/render/start
 * Sistema real de renderização com FFmpeg
 * Updated: Force recompilation
 */

import { NextRequest, NextResponse } from 'next/server';
import { prisma } from '@lib/prisma';
import { getSupabaseForRequest, supabaseAdmin } from '@lib/supabase/server';
import { addVideoJob } from '@lib/queue/render-queue';
import { type RenderConfig as QueueRenderConfig, type RenderSlide as QueueRenderSlide } from '@lib/queue/types';
import { jobManager } from '@lib/render/job-manager';
import { logger } from '@lib/logger';
import { rateLimit, getUserTier } from '@/middleware/rate-limiter';
import { requireEnvInProd } from '@lib/env';
import { applyRateLimit } from '@/lib/rate-limit';
import { cachedQuery, CacheTier, invalidatePattern } from '@lib/cache/redis-cache';
import { QUALITY_PRESETS, type VideoQuality } from '@lib/render/quality-presets';
import crypto from 'crypto';
import { z } from 'zod';

// ---- Zod Schemas for Input Validation ----

const slideSchema = z.object({
  id: z.string().optional(),
  imageUrl: z.string().optional().default(''),
  audioUrl: z.string().optional(),
  duration: z.number().min(1).max(300).optional().default(5),
  transition: z.enum(['fade', 'none']).optional().default('fade'),
  transitionDuration: z.number().min(0).max(5).optional().default(0.5),
  title: z.string().max(500).optional(),
  content: z.string().max(10000).optional(),
  avatarConfig: z.record(z.unknown()).optional(),
});

const renderConfigSchema = z.object({
  width: z.number().int().min(320).max(7680).optional(),
  height: z.number().int().min(240).max(4320).optional(),
  fps: z.number().int().min(15).max(120).optional(),
  quality: z.enum(['low', 'medium', 'high', 'ultra']).optional(),
  format: z.enum(['mp4', 'webm', 'mov']).optional().default('mp4'),
  codec: z.string().max(50).optional(),
  bitrate: z.string().max(20).optional(),
  audioCodec: z.string().max(20).optional(),
  audioBitrate: z.string().max(20).optional(),
  test: z.boolean().optional(),
}).optional();

const renderStartSchema = z.object({
  projectId: z.string().uuid('projectId deve ser um UUID válido'),
  slides: z.array(slideSchema).min(1, 'Pelo menos 1 slide é obrigatório').max(200, 'Máximo de 200 slides'),
  config: renderConfigSchema,
});

// Using queue types imported from @lib/queue/types

// Define interfaces locally to match API expectations
interface RenderConfig {
  width: number;
  height: number;
  fps: number;
  quality: 'low' | 'medium' | 'high' | 'ultra';
  format: string;
  codec: string;
  bitrate: string;
  audioCodec: string;
  audioBitrate: string;
  test?: boolean;
}

type PlanTier = 'free' | 'pro' | 'business';

const PLAN_RANK: Record<PlanTier, number> = {
  free: 0,
  pro: 1,
  business: 2,
};

const QUALITY_RANK: Record<RenderConfig['quality'], number> = {
  low: 0,
  medium: 1,
  high: 2,
  ultra: 3,
};

// ---- Derived from centralized QUALITY_PRESETS ----
// Maps subscription plan tiers to quality-presets requiresPlan values.
// This keeps render/start in sync with quality-presets.ts automatically.
function presetForQuality(q: RenderConfig['quality']): typeof QUALITY_PRESETS[VideoQuality] | undefined {
  const mapping: Record<string, VideoQuality> = { low: 'low', medium: 'medium', high: 'high', ultra: 'ultra' };
  return QUALITY_PRESETS[mapping[q]];
}

const PLAN_DEFAULTS: Record<PlanTier, Pick<RenderConfig, 'width' | 'height' | 'quality'>> = {
  free:     { width: QUALITY_PRESETS.medium.width, height: QUALITY_PRESETS.medium.height, quality: 'medium' },
  pro:      { width: QUALITY_PRESETS.high.width,   height: QUALITY_PRESETS.high.height,   quality: 'high' },
  business: { width: QUALITY_PRESETS.high.width,   height: QUALITY_PRESETS.high.height,   quality: 'high' },
};

const PLAN_LIMITS: Record<PlanTier, Pick<RenderConfig, 'width' | 'height' | 'quality'>> = {
  free:     { width: QUALITY_PRESETS.medium.width, height: QUALITY_PRESETS.medium.height, quality: 'medium' },
  pro:      { width: QUALITY_PRESETS.high.width,   height: QUALITY_PRESETS.high.height,   quality: 'high' },
  business: { width: QUALITY_PRESETS['4k'].width,  height: QUALITY_PRESETS['4k'].height,  quality: 'ultra' },
};

function getRequiredPlanForRender(
  width: number,
  height: number,
  quality: RenderConfig['quality']
): PlanTier {
  const withinFree =
    width <= PLAN_LIMITS.free.width &&
    height <= PLAN_LIMITS.free.height &&
    QUALITY_RANK[quality] <= QUALITY_RANK[PLAN_LIMITS.free.quality];

  if (withinFree) return 'free';

  const withinPro =
    width <= PLAN_LIMITS.pro.width &&
    height <= PLAN_LIMITS.pro.height &&
    QUALITY_RANK[quality] <= QUALITY_RANK[PLAN_LIMITS.pro.quality];

  if (withinPro) return 'pro';

  return 'business';
}

async function resolveUserPlan(userId: string): Promise<PlanTier> {
  try {
    const { data: subscription, error } = await supabaseAdmin
      .from('subscriptions' as never)
      .select('plan, status')
      .eq('user_id', userId)
      .single() as { data: { plan: string; status: string } | null; error: { message?: string; code?: string } | null };

    if (error) {
      const errorCode = (error as { code?: string }).code;
      if (errorCode !== 'PGRST116') {
        logger.warn('Erro ao buscar subscription para render', {
          userId,
          error: error.message,
          code: errorCode,
        });
      }
      return 'free';
    }

    const plan = (subscription?.plan as PlanTier) || 'free';
    const status = subscription?.status || 'active';
    const isActive = status === 'active' || status === 'trialing';

    return isActive ? plan : 'free';
  } catch (error: unknown) {
    logger.warn('Falha ao resolver plano para render', {
      userId,
      error: error instanceof Error ? error.message : 'Unknown error',
    });
    return 'free';
  }
}

export async function GET(req: NextRequest) {
  try {
    const { searchParams } = new URL(req.url);
    const action = searchParams.get('action');

    if (action === 'video-pipeline') {
      return NextResponse.json({
        success: true,
        message: 'Video pipeline endpoint working!',
        endpoint: '/api/render/start?action=video-pipeline',
        methods: ['GET', 'POST'],
        timestamp: new Date().toISOString()
      });
    }

    // Video test endpoint
    if (action === 'video-test') {
      return NextResponse.json({
        success: true,
        message: 'Video Test API is working!',
        endpoint: '/api/render/start?action=video-test',
        timestamp: new Date().toISOString(),
        status: 'operational',
        pipeline_status: 'ready',
        ffmpeg_available: true,
        render_queue_status: 'operational'
      });
    }

    // Create video job - GET is not allowed for job creation (anti-pattern)
    // Jobs must be created via POST for proper persistence and idempotency
    if (action === 'create-video-job') {
      return NextResponse.json({
        error: 'Job creation requires POST method',
        code: 'METHOD_NOT_ALLOWED',
        message: 'Use POST /api/render/start with projectId, slides, and config in body',
        documentation: {
          method: 'POST',
          endpoint: '/api/render/start',
          body: {
            projectId: 'string (required)',
            slides: 'array (required)',
            config: 'object (optional: width, height, fps, quality)'
          },
          headers: {
            'Content-Type': 'application/json',
            'Idempotency-Key': 'string (optional, for duplicate prevention)'
          }
        }
      }, { status: 405 });
    }

    return NextResponse.json({
      success: true,
      message: 'Render start endpoint',
      available_actions: ['video-pipeline', 'video-test'],
      note: 'Job creation requires POST method - see POST /api/render/start',
      usage: {
        video_pipeline: 'GET /api/render/start?action=video-pipeline',
        video_test: 'GET /api/render/start?action=video-test',
        create_job: 'POST /api/render/start (with projectId, slides, config in body)'
      }
    });

  } catch (error: unknown) {
    return NextResponse.json(
      { error: 'Erro interno do servidor' },
      { status: 500 }
    );
  }
}

export async function POST(req: NextRequest) {
  try {
    const blocked = await applyRateLimit(req, 'render-start', 10);
    if (blocked) return blocked;

    // Secure auth - x-user-id BLOCKED in production
    const { getAuthenticatedUserId } = await import('@lib/auth/safe-auth');
    const authResult = await getAuthenticatedUserId(req);
    if (!authResult.authenticated) {
      return NextResponse.json(
        { error: authResult.error },
        { status: 401 }
      );
    }
    const userId = authResult.userId;

    const userPlan = await resolveUserPlan(userId);

    // ========================================
    // VERIFICAÇÃO DE LIMITE DE VÍDEOS (MONETIZAÇÃO)
    // ========================================
    try {
      const limitResponse = await fetch(
        `${requireEnvInProd('NEXT_PUBLIC_APP_URL', 'http://localhost:3000')}/api/user/video-limit?userId=${userId}`
      );
      const limitData = await limitResponse.json();
      
      if (!limitData.can_create) {
        logger.warn('User hit video limit', { userId, videosUsed: limitData.videos_used, limit: limitData.video_limit });
        return NextResponse.json(
          { 
            error: 'Limite de vídeos atingido',
            code: 'VIDEO_LIMIT_EXCEEDED',
            videosUsed: limitData.videos_used,
            videoLimit: limitData.video_limit,
            planName: limitData.plan_name,
            upgradeUrl: '/pricing'
          },
          { status: 402 } // Payment Required
        );
      }
    } catch (limitError: unknown) {
      // Fail-closed: não iniciar render sem validar limite
      logger.error('Failed to check video limit, blocking render',
        limitError instanceof Error ? limitError : new Error(String(limitError)),
        { component: 'API: render/start', userId }
      );
      return NextResponse.json(
        {
          error: 'Não foi possível validar limite de vídeos no momento',
          code: 'VIDEO_LIMIT_CHECK_UNAVAILABLE',
          retryable: true,
        },
        { status: 503 }
      );
    }

    // Redis-backed distributed rate limiting
    // Tier-based limits: free=500/hr, basic=2000/hr, pro=5000/hr, enterprise=50000/hr
    const tier = await getUserTier(userId as string);
    const rateLimitResponse = await rateLimit(req, userId as string, tier);

    if (rateLimitResponse) {
      logger.warn('Rate limit exceeded', { userId, endpoint: '/api/render/start', tier });
      return rateLimitResponse;
    }

    const body = await req.json();

    // ---- Zod validation ----
    const parsed = renderStartSchema.safeParse(body);
    if (!parsed.success) {
      const firstError = parsed.error.errors[0];
      logger.warn('Render start validation failed', { errors: parsed.error.errors, userId });
      return NextResponse.json(
        {
          error: firstError?.message || 'Dados de entrada inválidos',
          code: 'VALIDATION_ERROR',
          details: parsed.error.errors.map(e => ({ path: e.path.join('.'), message: e.message })),
        },
        { status: 400 }
      );
    }

    const { projectId, slides, config } = parsed.data;

    const validQualities = ['low', 'medium', 'high', 'ultra'] as const;
    const planDefaults = PLAN_DEFAULTS[userPlan];
    const rawQuality = config?.quality;
    const quality: typeof validQualities[number] =
      typeof rawQuality === 'string' && validQualities.includes(rawQuality as typeof validQualities[number])
        ? rawQuality as typeof validQualities[number]
        : planDefaults.quality;
    const width = config?.width || planDefaults.width;
    const height = config?.height || planDefaults.height;
    const requiredPlan = getRequiredPlanForRender(width, height, quality);

    if (PLAN_RANK[userPlan] < PLAN_RANK[requiredPlan]) {
      logger.warn('Plano insuficiente para qualidade solicitada', {
        userId,
        currentPlan: userPlan,
        requiredPlan,
        width,
        height,
        quality,
      });

      return NextResponse.json(
        {
          error: 'Plano insuficiente para a qualidade solicitada',
          code: 'PLAN_REQUIRED',
          currentPlan: userPlan,
          requiredPlan,
          upgradeUrl: '/pricing',
        },
        { status: 402 }
      );
    }

    // Verifica se projeto existe e permissões (usando Redis cache)
    // Cache project ownership for 5 minutes - reduces DB load
    logger.info('Searching project', { projectId });
    const project = await cachedQuery(
      `project:${projectId}:owner:v2`,
      async () => {
        logger.info('Querying DB for project', { projectId });
        const p = await prisma.projects.findUnique({
          where: { id: projectId },
          select: { userId: true }
        });
        logger.info('DB Result', { p });
        return p;
      },
      CacheTier.SHORT // 5 minutes
    );

    if (!project) {
      logger.warn('Project not found', { projectId });
      return NextResponse.json(
        { error: 'Projeto não encontrado' },
        { status: 404 }
      );
    }

    // Check ownership or collaborator status
    let hasPermission = project.userId === userId;

    // If not owner, check collaborators table (also cached)
    if (!hasPermission) {
      const collaborator = await cachedQuery(
        `project:${projectId}:collaborator:${userId}`,
        async () => {
          return await prisma.project_collaborators.findFirst({
            where: {
              project_id: projectId,
              user_id: userId as string
            }
          });
        },
        CacheTier.SHORT // 5 minutes
      );

      if (collaborator) hasPermission = true;
    }

    if (!hasPermission) {
      return NextResponse.json(
        { error: 'Sem permissão para renderizar este projeto' },
        { status: 403 }
      );
    }

    // Configuração real do FFmpeg — defaults derived from centralized quality-presets
    const matchedPreset = presetForQuality(quality);
    const renderConfig: RenderConfig = {
      width,
      height,
      fps: config?.fps || (matchedPreset?.fps ?? 30),
      quality,
      format: config?.format || 'mp4',
      codec: config?.codec || (matchedPreset?.codec ?? 'h264'),
      bitrate: config?.bitrate || (matchedPreset?.bitrate ?? '5000k'),
      audioCodec: config?.audioCodec || 'aac',
      audioBitrate: config?.audioBitrate || (matchedPreset?.audioBitrate ?? '128k'),
      test: config?.test,
    };

    // Validar slides — já validados pelo Zod, apenas mapear para estrutura interna
    const validatedSlides = slides.map((slide, index) => ({
      id: slide.id || `slide_${index}`,
      orderIndex: index,
      imageUrl: slide.imageUrl || '',
      audioUrl: slide.audioUrl,
      duration: slide.duration,
      transition: slide.transition,
      transitionDuration: slide.transitionDuration,
      title: slide.title,
      content: slide.content,
      avatarConfig: slide.avatarConfig
    }));

    const traceId = crypto.randomUUID();
    const logContext = {
      traceId,
      projectId,
      userId: userId,
      slideCount: validatedSlides.length,
      config: renderConfig
    };

    logger.info('Iniciando renderização real', logContext);

    // Extract idempotency key from header (optional)
    const idempotencyKey = req.headers.get('Idempotency-Key') || undefined;

    if (idempotencyKey) {
      logger.info('Idempotency key provided', { idempotencyKey, projectId, userId });
    }

    // ========================================
    // FASE 2 - TRANSAÇÃO ATÔMICA (F2.1-F2.3)
    // ========================================
    let dbJobId: string | null = null;

    try {
      // 1. Create Job in Supabase (Critical for Worker Polling)
      dbJobId = await jobManager.createJob(userId as string, projectId, idempotencyKey);
      logger.info('Job criado no Supabase', { ...logContext, jobId: dbJobId });

      // 2. Add to Queue (Redis/BullMQ) - Atomic operation
      // If this fails, we rollback the DB job (F2.3)
      const queueSlides: QueueRenderSlide[] = validatedSlides.map((slide, idx) => ({
        id: slide.id,
        orderIndex: idx,
        title: slide.title,
        content: slide.content || '',
        duration: slide.duration || 5,
        transition: slide.transition === 'fade' ? 'fade' : 'none',
        transitionDuration: slide.transitionDuration || 0.5
      }));
      
      const queueConfig: QueueRenderConfig = {
        resolution: `${renderConfig.width}x${renderConfig.height}`,
        fps: renderConfig.fps,
        quality: renderConfig.quality,
        format: renderConfig.format as 'mp4' | 'webm' | 'mov',
        codec: renderConfig.codec,
        bitrate: renderConfig.bitrate,
        audioCodec: renderConfig.audioCodec,
        audioBitrate: renderConfig.audioBitrate,
        test: renderConfig.test
      };

      // F2.1: Enqueue com tratamento de erro
      await addVideoJob({
        jobId: dbJobId,
        projectId,
        slides: queueSlides as QueueRenderSlide[],
        config: queueConfig as QueueRenderConfig,
        userId: userId as string
      });

      logger.info('Job enfileirado com sucesso', { ...logContext, jobId: dbJobId });

      // Invalidate project cache
      await invalidatePattern(`project:${projectId}:*`);

      return NextResponse.json({
        success: true,
        jobId: dbJobId,
        traceId,
        projectId,
        slidesCount: validatedSlides.length,
        config: renderConfig,
        message: 'Renderização real iniciada com sucesso',
        statusUrl: `/api/render/status?jobId=${dbJobId}`
      });

    } catch (enqueueError: unknown) {
      // F2.2 & F2.3: Rollback - Evitar job órfão no DB
      if (dbJobId) {
        logger.error('Falha ao enfileirar job - executando rollback', enqueueError as Error, {
          ...logContext,
          jobId: dbJobId
        });

        await jobManager.markAsFailedEnqueue(
          dbJobId,
          enqueueError instanceof Error ? enqueueError.message : 'Unknown enqueue error'
        );
      }

      throw enqueueError; // Re-throw para catch externo
    }

  } catch (error: unknown) {
    // Parse projectId from request body if available
    let projectIdForLog: string | undefined;
    try {
      const body = await req.clone().json();
      projectIdForLog = body?.projectId;
    } catch {
      // Ignore parse errors for logging
    }
    
    logger.error('Erro ao iniciar render', error as Error, { 
      projectId: projectIdForLog 
    });
    
    return NextResponse.json(
      { 
        error: 'Erro ao iniciar render',
        details: error instanceof Error ? error.message : 'Erro desconhecido'
      },
      { status: 500 }
    );
  }
}


